package com.mabarcu.models;
import jakarta.persistence.*;
@Entity @Table(name="friends") public class Friend extends BaseEntity { private int userId; private String friendName; private String status; private String game; public Friend(){} public Friend(int userId,String friendName,String status,String game){this.userId=userId;this.friendName=friendName;this.status=status;this.game=game;} public int getUserId(){return userId;} public void setUserId(int userId){this.userId=userId;} public String getFriendName(){return friendName;} public void setFriendName(String friendName){this.friendName=friendName;} public String getStatus(){return status;} public void setStatus(String status){this.status=status;} public String getGame(){return game;} public void setGame(String game){this.game=game;} public String display(){return friendName+" • "+status+" • "+game;} }
